// Ergonomic wrappers over the GENERATED IPC client (`src/bindings.ts`).
//
// hard rule 2 / D17: types and the client are generated by tauri-specta, never
// hand-written. The generated `commands.*` return a typed `Result<T, AppError>`;
// these thin wrappers unwrap it to the throwing `Promise<T>` contract the UI
// already uses, and re-export the generated types so the rest of the app imports
// them from one place.
import { commands } from '../bindings';
import type {
  ActivityLog,
  AppError,
  Category,
  DayView,
  Exclusion,
  InstalledApp,
  Recap,
  Result,
  Rule,
  Setting,
  TimelineView,
  UncategorizedApp,
  WatcherStatus,
  WeekView,
} from '../bindings';

export type {
  ActivityLog,
  AppError,
  Category,
  CategoryRun,
  CategorySlice,
  DaySlice,
  DayView,
  Exclusion,
  InstalledApp,
  ProjectSlice,
  Recap,
  Rule,
  Setting,
  TimelineRun,
  TimelineSegment,
  TimelineView,
  UncategorizedApp,
  WatcherStatus,
  WeekView,
} from '../bindings';

/** Unwrap a generated `Result`, throwing a readable `Error` on the typed failure. */
function unwrap<T>(r: Result<T, AppError>): T {
  if (r.status === 'error') {
    const e = r.error;
    throw new Error('message' in e ? `${e.kind}: ${e.message}` : e.kind);
  }
  return r.data;
}

/**
 * Fetch activity logs from the backend for a given time range.
 *
 * @param startTime - Unix timestamp for range start
 * @param endTime - Unix timestamp for range end
 * @returns Array of activity logs
 */
export async function getActivityStats(
  startTime: number,
  endTime: number
): Promise<ActivityLog[]> {
  return unwrap(await commands.getActivityStats(startTime, endTime));
}

/**
 * Fetch the computed Day view (category aggregates + category-runs + recap) for a
 * Unix-second range. All numbers are computed in Rust (hard rule 6).
 */
export async function getDay(startTime: number, endTime: number): Promise<DayView> {
  return unwrap(await commands.getDay(startTime, endTime));
}

/**
 * Narrate the day's recap with the on-device Foundation Models sidecar, falling back to the
 * deterministic template (D48) on any failure. Async + lazy: call this AFTER the day loads
 * (`getDay` already returns the instant template recap) and upgrade the recap card in place
 * when it resolves. Numbers are computed in Rust (hard rule 6); the model only phrases them.
 */
export async function getRecap(startTime: number, endTime: number): Promise<Recap> {
  return unwrap(await commands.getRecap(startTime, endTime));
}

/**
 * Fetch the computed Week view: 7 day-slices (mini-dial runs + per-day totals) plus
 * week-level aggregates. `dayStarts` are the 7 local midnights (Unix secs); `weekEnd` is
 * the exclusive end of the last day. All numbers are computed in Rust (hard rule 6).
 */
export async function getWeek(dayStarts: number[], weekEnd: number): Promise<WeekView> {
  return unwrap(await commands.getWeek(dayStarts, weekEnd));
}

/**
 * Fetch the computed Timeline view: the day's category-runs, each with its inner app-switch
 * segments (the click-to-expand detail). Numbers are computed in Rust (hard rule 6).
 */
export async function getTimeline(startTime: number, endTime: number): Promise<TimelineView> {
  return unwrap(await commands.getTimeline(startTime, endTime));
}

// --- Categories (the `categories` table; IPC noun is "category", D31) ---

export async function getCategories(): Promise<Category[]> {
  return unwrap(await commands.getCategories());
}

export async function createCategory(name: string, color: string): Promise<number> {
  return unwrap(await commands.createCategory(name, color));
}

export async function updateCategory(id: number, name: string, color: string): Promise<void> {
  unwrap(await commands.updateCategory(id, name, color));
}

export async function deleteCategory(id: number): Promise<void> {
  unwrap(await commands.deleteCategory(id));
}

